package main

import (
	"fmt"
	"html"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html")

	// Get the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS
	sanitizedKeyword := html.EscapeString(keyword)

	// Create the HTML response
	htmlResponse := fmt.Sprintf(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Additional search results content would go here -->
</body>
</html>
`, sanitizedKeyword)

	// Write the response
	fmt.Fprint(w, htmlResponse)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Error starting server: %v\n", err)
	}
}

