package main

import (
	"fmt"
	"html"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// If no keyword is provided, show an empty search
	if keyword == "" {
		keyword = ""
	}

	// Create the HTML response
	htmlContent := fmt.Sprintf(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
</head>
<body>
    <div class="container">
        <h2>Search Results: %s</h2>
        <div id="results">
            <!-- Product results would go here -->
        </div>
    </div>
</body>
</html>
`, html.EscapeString(keyword))

	// Write the HTML response
	fmt.Fprint(w, htmlContent)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

